// ------------------------------------------------------------------------------------------------
HE_TEST(core, random, Random64_Construct)
{
    {
        Random64 r;
        HE_EXPECT_NE(r.m_state, 0);
    }

    {
        const uint64_t seed = 0x4458adf548;
        Random64 r(seed);
        HE_EXPECT_EQ(r.m_state, seed);
    }
}

